  log.innerHTML = state.chat.map(m => `<div class="msg ${m.role}">${m.text}</div>`).join('') || '<div class="msg ai">안녕하세요. 계약, 사고, 수재, 재보험, 약관·특약에 대해 질문해 주세요.</div>';
