  const inwardNotice = document.querySelector('#inward .notice');
  if(inwardNotice){
    inwardNotice.innerHTML = '마감 전 발생한 해외수재 계약은 플랫폼에서 실시간 수기관리하고, 월마감 전 기간계 입력 후 마감데이터 업로드 시 공식 데이터와 대사합니다.';
  }
